import React, { useState } from 'react';

const CrearOferta = () => {
  const [formData, setFormData] = useState({
    programa_formacion: '',
    modalidad: '',
    fecha_inicio: '',
    fecha_fin: '',
    cupo_maximo: '',
    municipio: '',
    empresa: '',
    nit: '',
    hora_inicio: '08:00',
    hora_fin: '12:00',
    dias: []
  });

  const handleChange = (e) => {
    const { name, value } = e.target;
    setFormData({
      ...formData,
      [name]: value
    });
  };

  const handleCheckboxChange = (e) => {
    const { value, checked } = e.target;
    if (checked) {
      setFormData({
        ...formData,
        dias: [...formData.dias, value]
      });
    } else {
      setFormData({
        ...formData,
        dias: formData.dias.filter(dia => dia !== value)
      });
    }
  };

  const handleSubmit = (e) => {
    e.preventDefault();
    console.log('Datos de la oferta:', formData);
    // Aquí irá la conexión con el backend
    alert('Oferta creada (simulación)');
  };

  const diasSemana = ['Lunes', 'Martes', 'Miércoles', 'Jueves', 'Viernes', 'Sábado'];

  return (
    <div style={styles.formContainer}>
      <h2 style={styles.formTitle}>➕ Crear Nueva Oferta</h2>
      <form onSubmit={handleSubmit} style={styles.form}>
        
        <div style={styles.formGroup}>
          <label style={styles.label}>Programa de Formación:</label>
          <select 
            name="programa_formacion" 
            value={formData.programa_formacion}
            onChange={handleChange}
            style={styles.select}
            required
          >
            <option value="">Seleccione...</option>
            <option value="69931b93fadde4f4fc73a0c0">EXPRESION ORAL Y CORPORAL</option>
            <option value="otro">OTRO PROGRAMA</option>
          </select>
        </div>

        <div style={styles.formGroup}>
          <label style={styles.label}>Modalidad:</label>
          <select 
            name="modalidad" 
            value={formData.modalidad}
            onChange={handleChange}
            style={styles.select}
            required
          >
            <option value="">Seleccione...</option>
            <option value="69931b20e3881b0ad35df08f">Presencial</option>
            <option value="virtual">Virtual</option>
          </select>
        </div>

        <div style={styles.formRow}>
          <div style={styles.formGroupHalf}>
            <label style={styles.label}>Fecha Inicio:</label>
            <input 
              type="date" 
              name="fecha_inicio"
              value={formData.fecha_inicio}
              onChange={handleChange}
              style={styles.input} 
              required 
            />
          </div>
          <div style={styles.formGroupHalf}>
            <label style={styles.label}>Fecha Fin:</label>
            <input 
              type="date" 
              name="fecha_fin"
              value={formData.fecha_fin}
              onChange={handleChange}
              style={styles.input} 
              required 
            />
          </div>
        </div>

        <div style={styles.formGroup}>
          <label style={styles.label}>Cupo Máximo:</label>
          <input 
            type="number" 
            name="cupo_maximo"
            value={formData.cupo_maximo}
            onChange={handleChange}
            style={styles.input} 
            placeholder="30" 
            required 
          />
        </div>

        <div style={styles.formGroup}>
          <label style={styles.label}>Municipio:</label>
          <select 
            name="municipio" 
            value={formData.municipio}
            onChange={handleChange}
            style={styles.select}
            required
          >
            <option value="">Seleccione...</option>
            <option value="699323051129ba026b77f6cd">Popayán</option>
          </select>
        </div>

        <div style={styles.formGroup}>
          <label style={styles.label}>Empresa Solicitante:</label>
          <input 
            type="text" 
            name="empresa"
            value={formData.empresa}
            onChange={handleChange}
            style={styles.input} 
            placeholder="Nombre de la empresa" 
            required 
          />
        </div>

        <div style={styles.formGroup}>
          <label style={styles.label}>NIT:</label>
          <input 
            type="text" 
            name="nit"
            value={formData.nit}
            onChange={handleChange}
            style={styles.input} 
            placeholder="123456789-0" 
            required 
          />
        </div>

        <div style={styles.formRow}>
          <div style={styles.formGroupHalf}>
            <label style={styles.label}>Hora Inicio:</label>
            <input 
              type="time" 
              name="hora_inicio"
              value={formData.hora_inicio}
              onChange={handleChange}
              style={styles.input} 
            />
          </div>
          <div style={styles.formGroupHalf}>
            <label style={styles.label}>Hora Fin:</label>
            <input 
              type="time" 
              name="hora_fin"
              value={formData.hora_fin}
              onChange={handleChange}
              style={styles.input} 
            />
          </div>
        </div>

        <div style={styles.formGroup}>
          <label style={styles.label}>Días:</label>
          <div style={styles.checkboxGroup}>
            {diasSemana.map(dia => (
              <label key={dia} style={styles.checkboxLabel}>
                <input 
                  type="checkbox" 
                  value={dia}
                  onChange={handleCheckboxChange}
                /> {dia}
              </label>
            ))}
          </div>
        </div>

        <button type="submit" style={styles.submitButton}>
          Guardar Oferta
        </button>
      </form>
    </div>
  );
};

const styles = {
  formContainer: {
    maxWidth: '800px',
    margin: '0 auto'
  },
  formTitle: {
    color: '#2c3e50',
    borderBottom: '2px solid #3498db',
    paddingBottom: '10px',
    marginBottom: '25px',
    fontSize: '24px'
  },
  form: {
    display: 'flex',
    flexDirection: 'column',
    gap: '20px'
  },
  formGroup: {
    display: 'flex',
    flexDirection: 'column',
    gap: '5px'
  },
  formRow: {
    display: 'flex',
    gap: '20px'
  },
  formGroupHalf: {
    flex: 1,
    display: 'flex',
    flexDirection: 'column',
    gap: '5px'
  },
  label: {
    fontSize: '14px',
    fontWeight: 'bold',
    color: '#34495e'
  },
  input: {
    padding: '10px',
    border: '1px solid #ddd',
    borderRadius: '4px',
    fontSize: '14px',
    transition: 'border-color 0.3s',
    outline: 'none',
    ':focus': {
      borderColor: '#3498db'
    }
  },
  select: {
    padding: '10px',
    border: '1px solid #ddd',
    borderRadius: '4px',
    fontSize: '14px',
    backgroundColor: 'white',
    cursor: 'pointer'
  },
  checkboxGroup: {
    display: 'flex',
    flexWrap: 'wrap',
    gap: '15px',
    padding: '10px 0'
  },
  checkboxLabel: {
    display: 'flex',
    alignItems: 'center',
    gap: '5px',
    fontSize: '14px',
    cursor: 'pointer'
  },
  submitButton: {
    backgroundColor: '#3498db',
    color: 'white',
    padding: '15px',
    border: 'none',
    borderRadius: '4px',
    fontSize: '16px',
    fontWeight: 'bold',
    cursor: 'pointer',
    marginTop: '20px',
    transition: 'background-color 0.3s',
    ':hover': {
      backgroundColor: '#2980b9'
    }
  }
};

export default CrearOferta;
